SELECT name
FROM subspecies
WHERE conservation_priority > 5;

SELECT COUNT(subspecies_id) AS high_priority_species_count
FROM subspecies
WHERE conservation_priority > 3;

SELECT binomial_name, conservation_priority
FROM subspecies
ORDER BY conservation_priority DESC;

SELECT name, range
FROM subspecies
WHERE genetic_diversity > (SELECT AVG(genetic_diversity) FROM subspecies);

SELECT name, genetic_diversity
FROM subspecies
ORDER BY genetic_diversity DESC;
